import { Component, OnInit } from '@angular/core';
import { Router, Scroll, NavigationEnd } from '@angular/router';
import { filter } from 'rxjs/operators';

import { ProjectService } from 'src/app/service/project.service';
import { MarkdownService } from 'ngx-markdown';
import { Anchor } from 'src/app/utils/Anchor';

@Component({
  selector: 'app-details',
  templateUrl: './details.component.html',
  styleUrls: ['./details.component.less']
})
export class DetailsComponent implements OnInit {

  articleDetail = {
    toc: '',
    _id: '',
    author: 'biaochenxuying',
    category: [],
    comments: [],
    create_time: '',
    desc: '',
    content: '',
    id: 16,
    img_url: '',
    numbers: 0,
    keyword: [],
    like_users: [],
    meta: { views: 0, likes: 0, comments: 0 },
    origin: 0,
    state: 1,
    tags: [],
    title: '',
    update_time: ''
  };

  constructor(private router: Router,
              private projectSe: ProjectService,
              private markSe: MarkdownService) {
    this.router.events.pipe(filter(e => e instanceof Scroll || e instanceof NavigationEnd))
      .subscribe(e => {
        if (e instanceof NavigationEnd) {
          const tree = this.router.parseUrl(this.router.url);
          if (tree.fragment) {
            const element = document.querySelector('.' + tree.fragment);
            if (element) { element.scrollIntoView(true); }
          }
        }
      });
  }

  ngOnInit(): void {

    this.markSe.renderer.heading = (text: string, level: number) => {
      const root = this.router.url.indexOf('#') !== -1 ? this.router.url.split('#')[0] : this.router.url;
      const anchor = Anchor.addAnchor(text, level, `${root}#`);
      return `<h${level} id="${anchor}" class="${anchor}">${text}</h${level}>`;
    };
    const trees = this.router.parseUrl(this.router.url);
    if (trees.queryParams) {
      this.projectSe.getDetails(trees.queryParams.id).subscribe((data) => {
        this.articleDetail = data.data;
        this.projectSe.getContent(`https://appppppen.github.io/articles/article${trees.queryParams.id}.md`).subscribe((s: string) => {
          this.articleDetail.content = this.markSe.compile(s);
          this.articleDetail.toc = Anchor.toHTML();
        });
        const keyword = this.articleDetail.keyword.join(',');
        const description = this.articleDetail.desc;
        const title = this.articleDetail.title;
        document.title = title;
        document.querySelector('#keywords').setAttribute('content', keyword);
        document.querySelector('#description').setAttribute('content', description);
        const tree = this.router.parseUrl(this.router.url);
        if (tree.fragment) {
          const element = document.querySelector('.' + tree.fragment);
          if (element) { element.scrollIntoView(true); }
        }
      });
    }
  }

}

