
export class Anchor {
  static toc = [];
  static index = 0;
  static addAnchor(t: string, l: number, links: string) {
    const anchors = `toc${l}${++this.index}`;
    this.toc.push({ anchor: anchors, level: l, text: t, link: links });
    return anchors;
  }

  static toHTML() {
    const levelStack = [];
    let result = '';
    const addStartUL = () => {
      result += '<ul class="anchor-ul" id="anchor-fix">';
    };
    const addEndUL = () => {
      result += '</ul>\n';
    };
    const addLI = (anchor: string, text: string, link: string) => {
      result += '<li><a class="toc-link" href="' + link + anchor + '">' + text + '<a></li>\n';
    };

    this.toc.forEach((item) => {
      let levelIndex = levelStack.indexOf(item.level);
      if (levelIndex === -1) {
        levelStack.unshift(item.level);
        addStartUL();
        addLI(item.anchor, item.text, item.link);
      } else if (levelIndex === 0) {
        addLI(item.anchor, item.text, item.link);
      } else {
        while (levelIndex--) {
          levelStack.shift();
          addEndUL();
        }
        addLI(item.anchor, item.text, item.link);
      }
    });

    while (levelStack.length) {
      levelStack.shift();
      addEndUL();
    }

    this.toc = [];
    this.index = 0;
    return result;
  }

}
