import { Component, OnInit, AfterViewInit } from '@angular/core';
import { HomeService, SwiperData } from 'src/app/service/home.service';
declare var Swiper: any;

@Component({
  selector: 'app-home',
  templateUrl: './home.component.html',
  styleUrls: ['./home.component.less']
})
export class HomeComponent implements OnInit, AfterViewInit {
  testSwiper: any;
  slides: SwiperData[] = [new SwiperData(''), new SwiperData(''), new SwiperData('')];

  constructor(private homeSvervice: HomeService) {
    this.homeSvervice.getDetails().subscribe((res) => {
      console.log('constructor');
      this.slides = res;
    });
  }

  ngOnInit(): void {
    document.title = 'Technical Arts';
  }

  ngAfterViewInit(): void {
    this.initSwiper();
  }

  private initSwiper() {
    console.log('ngAfterViewInit');
    this.testSwiper = new Swiper('.swiper-container', {
      direction: 'vertical',
      loop: false,
      speed: 1000,
      autoplay: false,
      observer: true,	// 轮播元素为内部动态添加必须加此 修改swiper自己或子元素时，自动初始化swiper
      observeParents: true,
      pagination: {
        el: '.swiper-pagination',
        clickable: true,
      },
      navigation: {
        // nextEl: '.swiper-button-next',
        // prevEl: '.swiper-button-prev',
      },
      scrollbar: {
        el: '.swiper-scrollbar',
      },
    });
  }
}
